    C = URIRef("http://qudt.org/vocab/unit/C")  # The SI unit of electric charge. One coulomb is the amount of charge accumulated in one second by a current of one ampere. Electricity is actually a flow of charged particles, such as electrons, protons, or ions. The charge on one of these particles is a whole-number multiple of the charge e on a single electron, and one coulomb represents a charge of approximately 6.241 506 x 1018 e. The coulomb is named for a French physicist, Charles-Augustin de Coulomb (1736-1806), who was the first to measure accurately the forces exerted between electric charges.
    C_M = URIRef("http://qudt.org/vocab/unit/C-M")  #    The $\text{Coulomb Meter (C-m)}$ is a unit in the category of Electric dipole moment.    It is also known as atomic unit, u.a., au, ua.    This unit is commonly used in the SI unit system.    Coulomb Meter (C-m) has a dimension of LTI where $L$ is length, $T$ is time, and $I$ is electric current.    This unit is the standard SI unit in this category.   
    C_M2 = URIRef("http://qudt.org/vocab/unit/C-M2")  # Coulomb Square Meter (C-m2) is a unit in the category of Electric quadrupole moment. This unit is commonly used in the SI unit system. Coulomb Square Meter (C-m2) has a dimension of L2TI where $L$ is length, $T$ is time, and $I$ is electric current. This unit is the standard SI unit in this category.
    C_M2_PER_KILOGM = URIRef("http://qudt.org/vocab/unit/C-M2-PER-KiloGM")  # product of the SI derived unit coulomb and the power of the SI base unit metre with the exponent 2 divided by the SI base unit kilogram
    C_M2_PER_V = URIRef("http://qudt.org/vocab/unit/C-M2-PER-V")  # Coulomb Square Meter (C-m2-per-volt) is a unit in the category of Electric polarizability.
    C_PER_CENTIM2 = URIRef("http://qudt.org/vocab/unit/C-PER-CentiM2")  # derived SI unit coulomb divided by the 0.0001-fold of the power of the SI base unit metre by exponent 2
    C_PER_CENTIM3 = URIRef("http://qudt.org/vocab/unit/C-PER-CentiM3")  # derived SI unit coulomb divided by the 0.000 001-fold of the power of the SI base unit metre by exponent 3
    C_PER_KILOGM = URIRef("http://qudt.org/vocab/unit/C-PER-KiloGM")  # $\textit{Coulomb Per Kilogram (C/kg)}$ is the unit in the category of Exposure. It is also known as coulombs per kilogram, coulomb/kilogram. This unit is commonly used in the SI unit system. Coulomb Per Kilogram (C/kg) has a dimension of $M^{-1}TI$ where $M$ is mass, $T$ is time, and $I$ is electric current. This unit is the standard SI unit in this category.
    C_PER_KILOGM_SEC = URIRef("http://qudt.org/vocab/unit/C-PER-KiloGM-SEC")  # The SI unit of exposure rate
    C_PER_M = URIRef("http://qudt.org/vocab/unit/C-PER-M")  # "Coulomb per Meter" is a unit for  'Electric Charge Line Density' expressed as $C/m$.
    C_PER_M2 = URIRef("http://qudt.org/vocab/unit/C-PER-M2")  # Coulomb Per Square Meter ($C/m^2$) is a unit in the category of Electric charge surface density. It is also known as coulombs per square meter, coulomb per square metre, coulombs per square metre, coulomb/square meter, coulomb/square metre. This unit is commonly used in the SI unit system. Coulomb Per Square Meter (C/m2) has a dimension of $L^{-2}TI$ where $L$ is length, $T$ is time, and $I$ is electric current. This unit is the standard SI unit in this category. 
    C_PER_M3 = URIRef("http://qudt.org/vocab/unit/C-PER-M3")  # Coulomb Per Cubic Meter ($C/m^{3}$) is a unit in the category of Electric charge density. It is also known as coulomb per cubic metre, coulombs per cubic meter, coulombs per cubic metre, coulomb/cubic meter, coulomb/cubic metre. This unit is commonly used in the SI unit system. Coulomb Per Cubic Meter has a dimension of $L^{-3}TI$ where $L$ is length, $T$ is time, and $I$ is electric current. This unit is the standard SI unit in this category.
    C_PER_MOL = URIRef("http://qudt.org/vocab/unit/C-PER-MOL")  #  ($C/mol$) is a unit in the category of Molar electric charge. It is also known as $coulombs/mol$. Coulomb Per Mol has a dimension of $TN{-1}I$ where $T$ is time, $N$ is amount of substance, and $I$ is electric current. This unit is the standard SI unit in this category.
    C_PER_MILLIM2 = URIRef("http://qudt.org/vocab/unit/C-PER-MilliM2")  # derived SI unit coulomb divided by the 0.000 001-fold of the power of the SI base unit metre by exponent 2
    C_PER_MILLIM3 = URIRef("http://qudt.org/vocab/unit/C-PER-MilliM3")  # derived SI unit coulomb divided by the 0.000 000 001-fold of the power of the SI base unit metre by exponent 3
    C2_M2_PER_J = URIRef("http://qudt.org/vocab/unit/C2-M2-PER-J")  # "Square Coulomb Square Meter per Joule" is a unit for  'Polarizability' expressed as $C^{2} m^{2} J^{-1}$.
    C3_M_PER_J2 = URIRef("http://qudt.org/vocab/unit/C3-M-PER-J2")  # "Cubic Coulomb Meter per Square Joule" is a unit for  'Cubic Electric Dipole Moment Per Square Energy' expressed as $C^{3} m^{3} J^{-2}$.
    C4_M4_PER_J3 = URIRef("http://qudt.org/vocab/unit/C4-M4-PER-J3")  # "Quartic Coulomb Meter per Cubic Energy" is a unit for  'Quartic Electric Dipole Moment Per Cubic Energy' expressed as $C^{4} m^{4} J^{-3}$.
