    CAL_15_DEG_C = URIRef("http://qudt.org/vocab/unit/CAL_15_DEG_C")  # unit for the quantity of heat which is required to warm up 1 g  of water, which is free of air, at a constant pressure of 101.325 kPa (the pressure of the standard atmosphere on sea level) from 14.5 degrees Celsius to 15.5 degrees Celsius
    CAL_20DEG_C = URIRef("http://qudt.org/vocab/unit/CAL_20DEG_C")  # unit for quantity of heat, which is to be required for 1 g air free water at a constant pressure from 101,325 kPa, to warm up the pressure of standard atmosphere at sea level, from 19.5 °C on 20.5 °C
    CAL_IT = URIRef("http://qudt.org/vocab/unit/CAL_IT")  # International Table calorie.
