    CD = URIRef("http://qudt.org/vocab/unit/CD")  # $\textit{Candela}$ is a unit for  'Luminous Intensity' expressed as $cd$.  The candela is the SI base unit of luminous intensity; that is, power emitted by a light source in a particular direction, weighted by the luminosity function (a standardized model of the sensitivity of the human eye to different wavelengths, also known as the luminous efficiency function). A common candle emits light with a luminous intensity of roughly one candela.
    CD_PER_FT2 = URIRef("http://qudt.org/vocab/unit/CD-PER-FT2")  # base unit SI candela divided by the power of the unit foot according to the Anglo-American and Imperial system of units by exponent 2
    CD_PER_IN2 = URIRef("http://qudt.org/vocab/unit/CD-PER-IN2")  # "Candela per Square Inch" is a unit for  'Luminance' expressed as $cd/in^{2}$.
    CD_PER_KILOLM = URIRef("http://qudt.org/vocab/unit/CD-PER-KiloLM")  # 
    CD_PER_LM = URIRef("http://qudt.org/vocab/unit/CD-PER-LM")  # 
    CD_PER_M2 = URIRef("http://qudt.org/vocab/unit/CD-PER-M2")  # The candela per square metre ($cd/m^2$) is the derived SI unit of luminance. The unit is based on the candela, the SI unit of luminous intensity, and the square metre, the SI unit of area. Nit (nt) is a deprecated non-SI name also used for this unit ($1 nit = 1 cd/m^2$). As a measure of light emitted per unit area, this unit is frequently used to specify the brightness of a display device. Most consumer desktop liquid crystal displays have luminances of 200 to 300 $cd/m^2$; the sRGB spec for monitors targets 80 cd/m2. HDTVs range from 450 to about 1000 cd/m2. Typically, calibrated monitors should have a brightness of $120 cd/m^2$. $Nit$ is believed to come from the Latin word nitere, to shine.
    CD_IN = URIRef("http://qudt.org/vocab/unit/CD_IN")  # obsolete, non-legal unit of the power in Germany relating to DIN 1301-3:1979
    CH = URIRef("http://qudt.org/vocab/unit/CH")  # A chain is a unit of length. It measures 66 feet, or 22 yards, or 100 links, or 4 rods. There are 10 chains in a furlong, and 80 chains in one statute mile. An acre is the area of 10 square chains (that is, an area of one chain by one furlong). The chain has been used for several centuries in Britain and in some other countries influenced by British practice.
    CHAIN_US = URIRef("http://qudt.org/vocab/unit/CHAIN_US")  # unit of the length according the Anglo-American system of units
    CHF_PER_KILOGM = URIRef("http://qudt.org/vocab/unit/CHF-PER-KiloGM")  # 
    CI = URIRef("http://qudt.org/vocab/unit/CI")  # The curie (symbol Ci) is a non-SI unit of radioactivity, named after Marie and Pierre Curie. It is defined as $1Ci = 3.7 \times 10^{10} decays\ per\ second$. Its continued use is discouraged. One Curie is roughly the activity of 1 gram of the radium isotope Ra, a substance studied by the Curies. The SI derived unit of radioactivity is the becquerel (Bq), which equates to one decay per second. Therefore: $1Ci = 3.7 \times 10^{10} Bq= 37 GBq$ and $1Bq \equiv 2.703 \times 10^{-11}Ci $.
    CI_PER_KILOGM = URIRef("http://qudt.org/vocab/unit/CI-PER-KiloGM")  # 1,000-fold of the unit curie divided by the SI base unit kilogram
    CLO = URIRef("http://qudt.org/vocab/unit/CLO")  # A C.G.S System unit for $\textit{Thermal Insulance}$ expressed as "clo".
    CM_H2O = URIRef("http://qudt.org/vocab/unit/CM_H2O")  # 
    CORD = URIRef("http://qudt.org/vocab/unit/CORD")  # The cord is a unit of measure of dry volume used in Canada and the United States to measure firewood and pulpwood. A cord is the amount of wood that, when 'ranked and well stowed' (arranged so pieces are aligned, parallel, touching and compact), occupies a volume of 128 cubic feet (3.62 cubic metres). This corresponds to a well stacked woodpile 4 feet (122 cm) wide, 4 feet (122 cm) high, and 8 feet (244 cm) long; or any other arrangement of linear measurements that yields the same volume. The name cord probably comes from the use of a cord or string to measure it. 
    COUNT = URIRef("http://qudt.org/vocab/unit/COUNT")  # "Count" is a unit for a dimensionless count.
    CP = URIRef("http://qudt.org/vocab/unit/CP")  # "Candlepower" (abbreviated as cp) is a now-obsolete unit which was used to express levels of light intensity in terms of the light emitted by a candle of specific size and constituents. In modern usage Candlepower equates directly to the unit known as the candela.
    CUP = URIRef("http://qudt.org/vocab/unit/CUP")  # "US Liquid Cup" is a unit for  'Liquid Volume' expressed as $cup$.
    CUP_US = URIRef("http://qudt.org/vocab/unit/CUP_US")  # unit of the volume according to the Anglo-American system of units
    CWT_LONG = URIRef("http://qudt.org/vocab/unit/CWT_LONG")  # "Hundred Weight - Long" is a unit for  'Mass' expressed as $cwt$.
    CWT_SHORT = URIRef("http://qudt.org/vocab/unit/CWT_SHORT")  # "Hundred Weight - Short" is a unit for  'Mass' expressed as $cwt$.
    CYC = URIRef("http://qudt.org/vocab/unit/CYC")  # 
    CYC_PER_SEC = URIRef("http://qudt.org/vocab/unit/CYC-PER-SEC")  # The "cycle per second" is a once-common English name for the unit of frequency now known as the hertz (Hz).
    C_AB = URIRef("http://qudt.org/vocab/unit/C_Ab")  # "abcoulomb" (abC or aC) or electromagnetic unit of charge (emu of charge) is the basic physical unit of electric charge in the cgs-emu system of units. One abcoulomb is equal to ten coulombs ($1\,abC\,=\,10\,C$).
    C_AB_PER_CENTIM2 = URIRef("http://qudt.org/vocab/unit/C_Ab-PER-CentiM2")  # Abcoulomb Per Square Centimeter is a unit in the category of Electric charge surface density. It is also known as abcoulombs per square centimeter, abcoulomb per square centimetre, abcoulombs per square centimetre, abcoulomb/square centimeter,abcoulomb/square centimetre. This unit is commonly used in the cgs unit system. Abcoulomb Per Square Centimeter (abcoulomb/cm2) has a dimension of $L_2TI$.  where $L$ is length, $T$ is time, and $I$ is electric current. It can be converted to the corresponding standard SI unit $C/m^2$ by multiplying its value by a factor of 100,000.
    C_STAT = URIRef("http://qudt.org/vocab/unit/C_Stat")  # The statcoulomb ($statC$) or franklin ($Fr$) or electrostatic unit of charge ($esu$) is the physical unit for electrical charge used in the centimetre-gram-second system of units (cgs) and Gaussian units. It is a derived unit given by $1\ statC = 1\ g\ cm\ s = 1\ erg\ cm$. The SI system of units uses the coulomb (C) instead. The conversion between C and statC is different in different contexts. The number 2997924580 is 10 times the value of the speed of light expressed in meters/second, and the conversions are exact except where indicated. The coulomb is an extremely large charge rarely encountered in electrostatics, while the statcoulomb is closer to everyday charges.
    C_STAT_PER_CENTIM2 = URIRef("http://qudt.org/vocab/unit/C_Stat-PER-CentiM2")  # $\textit{Statcoulomb per Square Centimeter}$ is a unit of measure for electric flux density and electric polarization.    One Statcoulomb per Square Centimeter is $2.15\times 10^9 \, coulomb\,per\,square\,inch$.   
    C_STAT_PER_MOL = URIRef("http://qudt.org/vocab/unit/C_Stat-PER-MOL")  # "Statcoulomb per Mole" is a unit of measure for the electical charge associated with one mole of a substance. The mole is a unit of measurement used in chemistry to express amounts of a chemical substance, defined as an amount of a substance that contains as many elementary entities (e.g., atoms, molecules, ions, electrons) as there are atoms in 12 grams of pure carbon-12 (12C), the isotope of carbon with atomic weight 12.
    CENTIBAR = URIRef("http://qudt.org/vocab/unit/CentiBAR")  # The bar is a non-SI unit of pressure, defined by the IUPAC as exactly equal to 100,000 Pa. It is about equal to the atmospheric pressure on Earth at sea level, and since 1982 the IUPAC has recommended that the standard for atmospheric pressure should be harmonized to $100,000\,Pa = 1 bar \approx 750.0616827 Torr$. Units derived from the bar are the megabar (symbol: Mbar), kilobar (symbol: kbar), decibar (symbol: dbar), centibar (symbol: cbar), and millibar (symbol: mbar or mb). They are not SI or cgs units, but they are accepted for use with the SI.
    CENTIC = URIRef("http://qudt.org/vocab/unit/CentiC")  # A CentiCoulomb is $10^{-2} C$.
    CENTIGM = URIRef("http://qudt.org/vocab/unit/CentiGM")  # 0,000 01-fold of the SI base unit kilogram
    CENTIGRAY = URIRef("http://qudt.org/vocab/unit/CentiGRAY")  # 0.01-fold of the unit gray
    CENTIL = URIRef("http://qudt.org/vocab/unit/CentiL")  # 0.01-fold of the unit litre
    CENTIM = URIRef("http://qudt.org/vocab/unit/CentiM")  # A centimetre is a unit of length in the metric system, equal to one hundredth of a metre, which is the SI base unit of length. Centi is the SI prefix for a factor of $10^{-2}$.  The centimetre is the base unit of length in the now deprecated centimetre-gram-second (CGS) system of units.
    CENTIM_PER_BAR = URIRef("http://qudt.org/vocab/unit/CentiM-PER-BAR")  # 0.01-fold of the SI base unit metre divided by the unit bar
    CENTIM_PER_HR = URIRef("http://qudt.org/vocab/unit/CentiM-PER-HR")  # 0.01-fold of the SI base unit metre divided by the unit hour
    CENTIM_PER_K = URIRef("http://qudt.org/vocab/unit/CentiM-PER-K")  # 0.01-fold of the SI base unit metre divided by the SI base unit kelvin
    CENTIM_PER_KILOYR = URIRef("http://qudt.org/vocab/unit/CentiM-PER-KiloYR")  # 
    CENTIM_PER_SEC = URIRef("http://qudt.org/vocab/unit/CentiM-PER-SEC")  # "Centimeter per Second" is a C.G.S System unit for  'Linear Velocity' expressed as $cm/s$.
    CENTIM_PER_SEC_BAR = URIRef("http://qudt.org/vocab/unit/CentiM-PER-SEC-BAR")  # 0.01-fold of the SI base unit metre divided by the product of the SI base unit second and the unit bar
    CENTIM_PER_SEC_K = URIRef("http://qudt.org/vocab/unit/CentiM-PER-SEC-K")  # 0.01-fold of the SI base unit metre divided by the product of the SI base unit second and the SI base unit Kelvin
    CENTIM_PER_SEC2 = URIRef("http://qudt.org/vocab/unit/CentiM-PER-SEC2")  # $\textit{Centimeter per Square Second}$ is a C.G.S System unit for  $\textit{Linear Acceleration}$ expressed as $cm/s^2$.
