    CENTIM3_PER_K = URIRef("http://qudt.org/vocab/unit/CentiM3-PER-K")  # 0,000 001-fold of the power of the SI base unit metre with the exponent 3 divided by the SI base unit kelvin
    CENTIM3_PER_M3 = URIRef("http://qudt.org/vocab/unit/CentiM3-PER-M3")  # volume ratio consisting of the 0.000 001-fold of the power of the SI base unit metre with the exponent 3 divided by the power of the SI base unit metre with the exponent 3
