    CENTIM3_PER_MIN_K = URIRef("http://qudt.org/vocab/unit/CentiM3-PER-MIN-K")  # 0.000001-fold of the power of the SI base unit metre with the exponent 3 divided by the product out of the unit minute and the SI base unit kelvin
