    DEG_PER_M = URIRef("http://qudt.org/vocab/unit/DEG-PER-M")  # A change of angle in one SI unit of length.
    DEG_PER_MIN = URIRef("http://qudt.org/vocab/unit/DEG-PER-MIN")  # A unit of measure for the rate of change of plane angle, $d\omega / dt$,  in durations of one minute.The vector $\omega$ is directed along the axis of rotation in the direction for which the rotation is clockwise.
