    DEG_F = URIRef("http://qudt.org/vocab/unit/DEG_F")  #    The unit $\textit{Degree Fahrenheit}$ is an Imperial unit for 'Thermodynamic Temperature' expressed as    $\circ\text{F}$   
    DEG_F_DAY = URIRef("http://qudt.org/vocab/unit/DEG_F-DAY")  # A unit of measurement that represents the difference between a reference temperature (typically 65°C) and the actual outdoor temperature over one day, used to estimate heating or cooling energy needs for buildings.
