    DEG_F_PER_HR = URIRef("http://qudt.org/vocab/unit/DEG_F-PER-HR")  # $\textit{Degree Fahrenheit per Hour}$ is a unit for 'Temperature Per Time' expressed as $degF / h$.
    DEG_F_PER_K = URIRef("http://qudt.org/vocab/unit/DEG_F-PER-K")  # traditional unit degree Fahrenheit for temperature according to the Anglo-American system of units divided by the SI base unit Kelvin
    DEG_F_PER_MIN = URIRef("http://qudt.org/vocab/unit/DEG_F-PER-MIN")  # $\textit{Degree Fahrenheit per Minute}$ is a unit for 'Temperature Per Time' expressed as $degF / m$.
    DEG_F_PER_SEC = URIRef("http://qudt.org/vocab/unit/DEG_F-PER-SEC")  # $\textit{Degree Fahrenheit per Second}$ is a unit for 'Temperature Per Time' expressed as $degF / s$.
