    GIBIBYTE = URIRef("http://qudt.org/vocab/unit/GibiBYTE")  # The gibibyte is a multiple of the unit byte for digital information storage. The prefix gibi means 1024^3
    GIGAA = URIRef("http://qudt.org/vocab/unit/GigaA")  # 1,000,000,000-fold of the unit ampere
    GIGABIT = URIRef("http://qudt.org/vocab/unit/GigaBIT")  # 1,000,000,000-fold of the unit bit
    GIGABIT_PER_M = URIRef("http://qudt.org/vocab/unit/GigaBIT-PER-M")  # 1,000,000,000-fold of the unit bit divided by the SI base unit metre
    GIGABIT_PER_SEC = URIRef("http://qudt.org/vocab/unit/GigaBIT-PER-SEC")  # A gigabit per second (Gbit/s or Gb/s) is a unit of data transfer rate equal to 1,000,000,000 bits per second.
    GIGABQ = URIRef("http://qudt.org/vocab/unit/GigaBQ")  # 1,000,000,000-fold of the derived SI unit becquerel
    GIGABYTE = URIRef("http://qudt.org/vocab/unit/GigaBYTE")  # The gigabyte is a multiple of the unit byte for digital information storage. The prefix giga means $10^9$ in the International System of Units (SI), therefore 1 gigabyte is $1,000,000,000 \; bytes$. The unit symbol for the gigabyte is $GB$ or $Gbyte$, but not $Gb$ (lower case b) which is typically used for the gigabit. Historically, the term has also been used in some fields of computer science and information technology to denote the $gibibyte$, or $1073741824 \; bytes$.
    GIGABYTE_PER_SEC = URIRef("http://qudt.org/vocab/unit/GigaBYTE-PER-SEC")  # 1,000,000,000-fold of the unit byte divided by the SI base unit second
    GIGABASEPAIR = URIRef("http://qudt.org/vocab/unit/GigaBasePair")  # A gigabase (abbreviated Gb, or Gbp for gigabase pairs.) is a unit of measurement used to help designate the length of DNA. One gigabase is equal to 1 billion bases. 
