    GIGAEV = URIRef("http://qudt.org/vocab/unit/GigaEV")  # "Giga Electron Volt" is a unit for  'Energy And Work' expressed as $GeV$.
    GIGAFLOPS = URIRef("http://qudt.org/vocab/unit/GigaFLOPS")  # 1,000,000,000-fold of the unit floating point operations divided by the SI base unit second
    GIGAHZ = URIRef("http://qudt.org/vocab/unit/GigaHZ")  # The hertz (symbol Hz) is the SI unit of frequency defined as the number of cycles per second of a periodic phenomenon. A GigaHertz is $10^{9} hz$.
    GIGAHZ_M = URIRef("http://qudt.org/vocab/unit/GigaHZ-M")  # product of the 1,000,000,000-fold of the SI derived unit hertz and the SI base unit metre
    GIGAJ = URIRef("http://qudt.org/vocab/unit/GigaJ")  # 1,000,000,000-fold of the SI derived unit joule
    GIGAJ_PER_HR = URIRef("http://qudt.org/vocab/unit/GigaJ-PER-HR")  # SI derived unit Gigajoule divided by the 3600 times the SI base unit second
    GIGAJ_PER_M2 = URIRef("http://qudt.org/vocab/unit/GigaJ-PER-M2")  # Gigajoule Per Square Meter ($J/m^2$) is a unit in the category of Energy density. It is also known as Gigajoules per square meter, Gigajoule per square metre, Gigajoule/square meter, Gigajoule/square metre.
    GIGAJ_PER_SEC = URIRef("http://qudt.org/vocab/unit/GigaJ-PER-SEC")  # 1,000,000,000-fold of the SI derived unit joule divided by the SI base unit second
    GIGAN = URIRef("http://qudt.org/vocab/unit/GigaN")  # 
    GIGAN_M_PER_M2 = URIRef("http://qudt.org/vocab/unit/GigaN-M-PER-M2")  # 1,000,000,000-fold of the SI derived unit newton divided by the SI base unit metre to the power two
    GIGAOHM = URIRef("http://qudt.org/vocab/unit/GigaOHM")  # 1,000,000,000-fold of the SI derived unit ohm
    GIGAOHM_M = URIRef("http://qudt.org/vocab/unit/GigaOHM-M")  # 1,000,000,000-fold of the product out of the SI derived unit ohm and the SI unit metre
    GIGAOHM_PER_M = URIRef("http://qudt.org/vocab/unit/GigaOHM-PER-M")  # 1,000,000,000-fold of the SI derived unit ohm divided by the SI unit metre
