    M_K_PER_W = URIRef("http://qudt.org/vocab/unit/M-K-PER-W")  # $\textit{Meter Kelvin per Watt}$ is a unit for 'Thermal Resistivity' expressed as $K-m/W$.
    M_KILOGM = URIRef("http://qudt.org/vocab/unit/M-KiloGM")  # product of SI base units metre and kilogram given as dimensional product dim Q = L**$a} M**$b} T**$g} I**$d} $TH**$e} N**$z} J**$i}
