    M_PER_DEG_C_M = URIRef("http://qudt.org/vocab/unit/M-PER-DEG_C-M")  # SI base unit metre divided by the product of the unit degree Celsius and the SI base unit metre
    M_PER_FARAD = URIRef("http://qudt.org/vocab/unit/M-PER-FARAD")  # 
