    V_PER_CENTIM = URIRef("http://qudt.org/vocab/unit/V-PER-CentiM")  # derived SI unit volt divided by the 0.01-fold of the SI base unit metre
    V_PER_IN = URIRef("http://qudt.org/vocab/unit/V-PER-IN")  # SI derived unit volt divided by the unit inch according to the Anglo-American and the Imperial system of units
    V_PER_K = URIRef("http://qudt.org/vocab/unit/V-PER-K")  # 
