    V_PER_SEC = URIRef("http://qudt.org/vocab/unit/V-PER-SEC")  # 'Volt per Second' is a unit of magnetic flux equaling one weber. This is the flux passing through a conducting loop and reduced to zero at a uniform rate in one second inducing an electric potential of one volt in the loop. 
