    W_HR_PER_M2 = URIRef("http://qudt.org/vocab/unit/W-HR-PER-M2")  # A unit of energy per unit area, equivalent to 3,600 joules per square metre.
    W_HR_PER_M3 = URIRef("http://qudt.org/vocab/unit/W-HR-PER-M3")  # The watt hour per cubic meter is a unit of energy density, equal to 3,600 joule per cubic meter.
    W_M_PER_M2_SR = URIRef("http://qudt.org/vocab/unit/W-M-PER-M2-SR")  # The power per unit area of radiation of a given wavenumber illuminating a target at a given incident angle.
    W_M2 = URIRef("http://qudt.org/vocab/unit/W-M2")  # product of the SI derived unit watt and the power of the SI base unit metre with the exponent 2
    W_M2_PER_SR = URIRef("http://qudt.org/vocab/unit/W-M2-PER-SR")  # 
