    W_PER_M2_K = URIRef("http://qudt.org/vocab/unit/W-PER-M2-K")  #    The unit $\textit{Watt Per Square Meter Kelvin }$ ($W m^{-2} K^{-1}$) is a unit in the category of Thermal heat transfer coefficient.    It is also known as $\textit{watt/square meter-kelvin}$.    This unit is commonly used in the SI unit system.    $\textit{Watt Per Square Meter Kelvin }$ has a dimension of $MT^{-1}Q^{-1}$ where $M$ is mass, $T$ is time, and $Q$ is temperature.    This unit is the standard SI unit in this category.   
    W_PER_M2_K4 = URIRef("http://qudt.org/vocab/unit/W-PER-M2-K4")  # Watt Per Square Meter Per Quartic Kelvin ($W/m2\cdotK4)$ is a unit in the category of light.
    W_PER_M2_M = URIRef("http://qudt.org/vocab/unit/W-PER-M2-M")  # 
    W_PER_M2_M_SR = URIRef("http://qudt.org/vocab/unit/W-PER-M2-M-SR")  # 
