    W_PER_M2_NANOM_SR = URIRef("http://qudt.org/vocab/unit/W-PER-M2-NanoM-SR")  # 
    W_PER_M2_PA = URIRef("http://qudt.org/vocab/unit/W-PER-M2-PA")  # Watt Per Square Meter Per Pascal ($W/m^2-pa$) is a unit of Evaporative Heat Transfer.
    W_PER_M2_SR = URIRef("http://qudt.org/vocab/unit/W-PER-M2-SR")  # $\textit{Watt per steradian per square metre}$ is the SI unit of radiance ($W·sr^{-1}·m^{-2}$),   while that of spectral radiance in frequency is the watt per steradian per square metre   per hertz ($W·sr^{-1}·m^{-2}·Hz^{-1}$) and that of spectral radiance in wavelength is   the watt per steradian per square metre, per metre ($W·sr^{-1}·m^{-3}$),   commonly the watt per steradian per square metre per nanometre ($W·sr^{-1}·m^{-2}·nm^{-1}$).    It has a dimension of $ML^{-4}T^{-3}$ where $M$ is mass, $L$ is length, and $T$ is time.    This unit is the standard SI unit in this category."   
    W_PER_M3 = URIRef("http://qudt.org/vocab/unit/W-PER-M3")  # SI derived unit watt divided by the power of the SI base unit metre with the exponent 3
    W_PER_SR = URIRef("http://qudt.org/vocab/unit/W-PER-SR")  # $\textit{Watt Per Steradian (W/sr)}$ is the unit in the category of Radiant intensity. It is also known as watts per steradian. This unit is commonly used in the SI unit system. Watt Per Steradian (W/sr) has a dimension of $M\cdot L^{-2}\cdot T^{-3}$ where $M$ is mass, $L$ is length, and $T$ is time. This unit is the standard SI unit in this category.
    W_SEC = URIRef("http://qudt.org/vocab/unit/W-SEC")  # product of the SI derived unit watt and SI base unit second
    W_SEC_PER_M2 = URIRef("http://qudt.org/vocab/unit/W-SEC-PER-M2")  # 
    W0DOT = URIRef("http://qudt.org/vocab/unit/W0dot")  # 
    WB = URIRef("http://qudt.org/vocab/unit/WB")  # The SI unit of magnetic flux. "Flux" is the rate (per unit of time) at which something crosses a surface perpendicular to the flow. The weber is a large unit, equal to $10^{8}$ maxwells, and practical fluxes are usually fractions of one weber. The weber is the magnetic flux which, linking a circuit of one turn, would produce in it an electromotive force of 1 volt if it were reduced to zero at a uniform rate in 1 second. In SI base units, the dimensions of the weber are $(kg \cdot m^2)/(s^2 \cdot A)$. The weber is commonly expressed in terms of other derived units as the Tesla-square meter ($T \cdot m^2$), volt-seconds ($V \cdot s$), or joules per ampere ($J/A$).
    WB_M = URIRef("http://qudt.org/vocab/unit/WB-M")  # 
    WB_PER_M = URIRef("http://qudt.org/vocab/unit/WB-PER-M")  # SI derived unit weber divided by the SI base unit metre
    WB_PER_MILLIM = URIRef("http://qudt.org/vocab/unit/WB-PER-MilliM")  # derived SI unit weber divided by the 0.001-fold of the SI base unit metre
    WK = URIRef("http://qudt.org/vocab/unit/WK")  # Mean solar week
    WK_PER_NUM = URIRef("http://qudt.org/vocab/unit/WK-PER-NUM")  # 
    YD = URIRef("http://qudt.org/vocab/unit/YD")  # A yard is a unit of length in several different systems including United States customary units, Imperial units and the former English units. It is equal to 3 feet or 36 inches. Under an agreement in 1959 between Australia, Canada, New Zealand, South Africa, the United Kingdom and the United States, the yard (known as the "international yard" in the United States) was legally defined to be exactly 0.9144 metres.
    YD_PER_DEG_F = URIRef("http://qudt.org/vocab/unit/YD-PER-DEG_F")  # unit yard according to the Anglo-American and the Imperial system of units divided by the unit for temperature degree Fahrenheit
    YD_PER_HR = URIRef("http://qudt.org/vocab/unit/YD-PER-HR")  # unit yard according to the Anglo-American and Imperial system of units divided by the unit hour
    YD_PER_MIN = URIRef("http://qudt.org/vocab/unit/YD-PER-MIN")  # unit yard according to the Anglo-American and Imperial system of units divided by the unit minute
    YD_PER_PSI = URIRef("http://qudt.org/vocab/unit/YD-PER-PSI")  # unit yard according to the Anglo-American and the Imperial system of units divided by the composed unit for pressure (pound-force per square inch)
    YD_PER_SEC = URIRef("http://qudt.org/vocab/unit/YD-PER-SEC")  # unit yard according to the Anglo-American and Imperial system of units divided by the SI base unit second
    YD_PER_SEC2 = URIRef("http://qudt.org/vocab/unit/YD-PER-SEC2")  # unit of the length according to the Anglo-American and Imperial system of units divided by the power of the SI base unit second by exponent 2
    YD2 = URIRef("http://qudt.org/vocab/unit/YD2")  # The square yard is an imperial/US customary unit of area, formerly used in most of the English-speaking world but now generally replaced by the square metre outside of the U.S. , Canada and the U.K. It is defined as the area of a square with sides of one yard in length. (Gaj in Hindi).
    YD3 = URIRef("http://qudt.org/vocab/unit/YD3")  # A cubic yard is an Imperial / U.S. customary unit of volume, used in the United States, Canada, and the UK. It is defined as the volume of a cube with sides of 1 yard in length.
    YD3_PER_DAY = URIRef("http://qudt.org/vocab/unit/YD3-PER-DAY")  # power of the unit yard according to the Anglo-American and the Imperial system of units with the exponent 3 divided by the unit for time day
    YD3_PER_DEG_F = URIRef("http://qudt.org/vocab/unit/YD3-PER-DEG_F")  # power of the unit yard according to the Anglo-American and the Imperial system of units with the exponent 3 divided by the unit for temperature degree Fahrenheit
    YD3_PER_HR = URIRef("http://qudt.org/vocab/unit/YD3-PER-HR")  # power of the unit yard according to the Anglo-American and the Imperial system of units with the exponent 3 divided by the unit for the time hour
    YD3_PER_MIN = URIRef("http://qudt.org/vocab/unit/YD3-PER-MIN")  # $\textit{Cubic Yard per Minute}$ is an Imperial unit for 'Volume Per Unit Time' expressed as $yd^{3}/min$.   
    YD3_PER_PSI = URIRef("http://qudt.org/vocab/unit/YD3-PER-PSI")  # power of the unit yard according to the Anglo-American and the Imperial system of units with the exponent 3 divided by the composed unit for pressure (pound-force per square inch)
    YD3_PER_SEC = URIRef("http://qudt.org/vocab/unit/YD3-PER-SEC")  # power of the unit and the Anglo-American and Imperial system of units with the exponent 3 divided by the SI base unit second
    YR = URIRef("http://qudt.org/vocab/unit/YR")  # A year is any of the various periods equated with one passage of Earth about the Sun, and hence of roughly 365 days. The familiar calendar has a mixture of 365- and 366-day years, reflecting the fact that the time for one complete passage takes about 365¼ days; the precise value for this figure depends on the manner of defining the year.
    YR_PER_NUM = URIRef("http://qudt.org/vocab/unit/YR-PER-NUM")  # 
    YR_COMMON = URIRef("http://qudt.org/vocab/unit/YR_Common")  # 31,536,000-fold of the SI base unit second according a common year with 365 days
    YR_METROLOGY = URIRef("http://qudt.org/vocab/unit/YR_Metrology")  # 31,557,600-fold of the SI base unit second according to one year with 365.25 days as physical quantity in the metrology
    YR_SIDEREAL = URIRef("http://qudt.org/vocab/unit/YR_Sidereal")  # A sidereal year is the time taken for Sun to return to the same position with respect to the stars of the celestial sphere.
    YR_TROPICAL = URIRef("http://qudt.org/vocab/unit/YR_TROPICAL")  # <p>A tropical year (also known as a solar year), for general purposes, is the length of time that the Sun takes to return to the same position in the cycle of seasons, as seen from Earth; for example, the time from vernal equinox to vernal equinox, or from summer solstice to summer solstice. Because of the precession of the equinoxes, the seasonal cycle does not remain exactly synchronised with the position of the Earth in its orbit around the Sun. As a consequence, the tropical year is about 20 minutes shorter than the time it takes Earth to complete one full orbit around the Sun as measured with respect to the fixed stars. Since antiquity, astronomers have progressively refined the definition of the tropical year, and currently define it as the time required for the mean Sun's tropical longitude (longitudinal position along the ecliptic relative to its position at the vernal equinox) to increase by 360 degrees (that is, to complete one full seasonal circuit).</p>
    YOCTOC = URIRef("http://qudt.org/vocab/unit/YoctoC")  # A YoctoCoulomb is $10^{-24} C$.
    YOTTAC = URIRef("http://qudt.org/vocab/unit/YottaC")  # A YottaCoulomb is $10^{24} C$.
    Z = URIRef("http://qudt.org/vocab/unit/Z")  # In chemistry and physics, the atomic number (also known as the proton number) is the number of protons found in the nucleus of an atom and therefore identical to the charge number of the nucleus. It is conventionally represented by the symbol Z. The atomic number uniquely identifies a chemical element. In an atom of neutral charge, the atomic number is also equal to the number of electrons.
    ZOLL = URIRef("http://qudt.org/vocab/unit/ZOLL")  # length measure corresponding to the imperial unit "inch"
    ZEPTOC = URIRef("http://qudt.org/vocab/unit/ZeptoC")  # A ZeptoCoulomb is $10^{-21} C$.
